{
  "summary": "A procedural burst of 4-pointed golden stars designed for UI feedback. It uses a generated texture to avoid external assets, featuring a rapid scale-up and fade-out with additive blending for a 'magical' glow effect.",
  "duration_ms": 600,
  "palette": [
    "#FFFFFF",
    "#FFF7AE",
    "#FFD700",
    "#B8860B"
  ],
  "particle_config": {
    "count": 5,
    "lifespan": 500,
    "velocity": {
      "min": 60,
      "max": 120
    },
    "scale": {
      "start": 0.1,
      "end": 1.2,
      "ease": "Back.easeOut"
    },
    "alpha": {
      "start": 1,
      "end": 0,
      "ease": "Power2"
    },
    "rotation": {
      "start": 0,
      "end": 90
    },
    "blend_mode": "ADD",
    "gravity_y": 100
  },
  "typescript": "function spawnSparkles(scene: Phaser.Scene, x: number, y: number): void {
  const textureKey = 'procedural_star';
  if (!scene.textures.exists(textureKey)) {
    const size = 32;
    const center = size / 2;
    const inner = 4;
    const graphics = scene.make.graphics({ x: 0, y: 0, add: false });
    graphics.fillStyle(0xffffff);
    graphics.beginPath();
    graphics.moveTo(center, 0);
    graphics.lineTo(center + inner, center - inner);
    graphics.lineTo(size, center);
    graphics.lineTo(center + inner, center + inner);
    graphics.lineTo(center, size);
    graphics.lineTo(center - inner, center + inner);
    graphics.lineTo(0, center);
    graphics.lineTo(center - inner, center - inner);
    graphics.closePath();
    graphics.fillPath();
    graphics.generateTexture(textureKey, size, size);
  }

  const emitter = scene.add.particles(x, y, textureKey, {
    speed: { min: 60, max: 140 },
    angle: { min: 0, max: 360 },
    scale: { start: 0.2, end: 0.8, ease: 'Back.out' },
    alpha: { start: 1, end: 0 },
    rotate: { start: 0, end: 180 },
    lifespan: 600,
    tint: [0xFFFFFF, 0xFFF7AE, 0xFFD700],
    blendMode: 'ADD',
    gravityY: 150,
    emitting: false
  });

  emitter.explode(6);
  scene.time.delayedCall(800, () => emitter.destroy());
}"
}
}
